import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:firebase_core/firebase_core.dart';
// import 'firebase_options.dart'; // Generated by flutterfire configure
import 'core/routing/app_router.dart';
import 'package:google_fonts/google_fonts.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  
  // TODO: FIREBASE INITIALIZATION
  // 1. Create a project at https://console.firebase.google.com/
  // 2. Run `dart pub global activate flutterfire_cli`
  // 3. Run `flutterfire configure` in your terminal to link the project
  await Firebase.initializeApp();

  runApp(
    const ProviderScope(
      child: ResultPublishingApp(),
    ),
  );
}

class ResultPublishingApp extends StatelessWidget {
  const ResultPublishingApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp.router(
      title: 'Universal Results',
      debugShowCheckedModeBanner: false,
      routerConfig: appRouter,
      theme: ThemeData(
        colorScheme: const ColorScheme.light(
          primary: Color(0xFF0F172A), // Dark Slate
          secondary: Color(0xFFFF5722), // Sporty Orange
          surface: Colors.white,
        ),
        scaffoldBackgroundColor: const Color(0xFFF8F9FA),
        textTheme: GoogleFonts.interTextTheme(
          Theme.of(context).textTheme,
        ),
        useMaterial3: true,
      ),
    );
  }
}
